def range_summary(nums):
    if not nums:
        return ''
    sorted_list = sorted(set(nums))
    runs = []
    start, end = sorted_list[0], sorted_list[0]
    for i in sorted_list:
        if i == start + 1:
            end = i
        elif end != i:
            runs.append(f'{start}-{end}')
            start = i
            end = i
    runs.append(str(end))
    return ', '.join(runs) if runs else '{}'.format(sorted_list[0])
